import{_ as t,o as a,c as o,ag as e}from"./chunks/framework.DtEl18Xn.js";const s="/getbiji-docs-v3/images/C3PgbmanaoSk1TxbXcPcbLvrn7f.png",r="/getbiji-docs-v3/images/EjFbbkfVPoTVybx0u2Cce3fZnMe.png",n="/getbiji-docs-v3/images/QniAbytR4o5wbRx4zJecqzj1nTh.png",i="/getbiji-docs-v3/images/HkXtbDjguoqaTGxHvFdcemMpnHf.png",g="/getbiji-docs-v3/images/YpTPbLKFpoCWbYx7jVVceS6JnUb.png",c="/getbiji-docs-v3/images/L57Fbrrpro9mtkxtVDAcPyZvnCg.png",_="/getbiji-docs-v3/images/MCvvbmELFo5qAxxaXDOckSiPnDg.png",m="/getbiji-docs-v3/images/OufGblYm3o9F9UxyiPxcVEKFnIg.png",l="/getbiji-docs-v3/images/EyXwbzIb8oNkXcxs1fBcPoAYnec.png",b="/getbiji-docs-v3/images/LlKUb5qv3ot08SxzeUJcwCjznib.png",d="/getbiji-docs-v3/images/U0mqb15m6olTeKxTntgcufOgnCb.png",k=JSON.parse('{"title":"基于「得到App」提问，快速写稿","description":"","frontmatter":{"title":"基于「得到App」提问，快速写稿","category":"最佳实践-原来还能这么用","lastUpdated":"2026-03-14T15:01:01.788Z"},"headers":[],"relativePath":"最佳实践-原来还能这么用/基于得到app提问快速写稿.md","filePath":"最佳实践-原来还能这么用/基于得到app提问快速写稿.md"}'),h={name:"最佳实践-原来还能这么用/基于得到app提问快速写稿.md"};function x(f,p,q,u,A,v){return a(),o("div",null,[...p[0]||(p[0]=[e('<h1 id="基于「得到app」提问-快速写稿" tabindex="-1">基于「得到App」提问，快速写稿 <a class="header-anchor" href="#基于「得到app」提问-快速写稿" aria-label="Permalink to &quot;基于「得到App」提问，快速写稿&quot;">​</a></h1><p>公众号原文链接：<a href="https://mp.weixin.qq.com/s/5_eIt7e__w16SMCwUwkFng" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/5_eIt7e__w16SMCwUwkFng</a></p><p>原创 曹将 曹将 <em>2025年07月14日 20:25 广东</em></p><p><img src="'+s+'" alt=""></p><p>作者：曹将</p><p>编辑：泽涛</p><h1 id="_01" tabindex="-1"><strong>01</strong> <a class="header-anchor" href="#_01" aria-label="Permalink to &quot;**01**&quot;">​</a></h1><p>Get 笔记最近更新了。</p><p>在隐蔽的地方，它上线了一个让我激动到失眠的功能：「得到 App 」知识库！</p><p>这是什么意思？</p><p>就是说，我提了问题，它就可以基于「得到 App 」 里的课程、电子书和听书内容，给我输出答案。</p><p><img src="'+r+'" alt=""></p><p><strong>↑ 如何基于「得到 App 」提问</strong></p><p>为什么我会这么激动？</p><p>因为，一个 Ai 效果好不好，核心就在于投喂它的内容质量高不高。而这一次，Get 笔记直接把「得到 App 」的内容变成了内在知识库，输出的品质马上就上了一个台阶！</p><p>毕竟，得到的内容品控，在业内也是领先的。</p><p>你肯定会问了，<strong>这个库有什么用处？</strong></p><h2 id="_02" tabindex="-1"><strong>02</strong> <a class="header-anchor" href="#_02" aria-label="Permalink to &quot;**02**&quot;">​</a></h2><p>比如我最近在梳理一套沟通的基本框架，希望找到一些质量比较高的案例，于是，我就在对话中，请它：从「得到 App 」里，找到相关的案例论据。</p><p>不得不说，质量真的不错！</p><p><img src="'+n+'" alt=""></p><p><strong>↑ 沟通的基本框架</strong></p><p><img src="'+i+'" alt=""></p><p><strong>↑ 基于得到内容给出的建议</strong></p><h2 id="_03" tabindex="-1"><strong>03</strong> <a class="header-anchor" href="#_03" aria-label="Permalink to &quot;**03**&quot;">​</a></h2><p>这个升级还有一个好处，那就是用于「写稿」，特别是写那种「通俗易懂」的稿子。</p><p>为什么这么说？得到最擅长的事，就是把一个道理说得简单易懂。</p><p>举个例子，明天你被邀请去跟新员工做沟通，请它基于得到内容输出一份发言稿素材。我给的指令是：</p><p>明天我要去跟新员工交流，请围绕「向内探索」和「向上生长」两个维度，基于「得到 app」中的内容，帮我写一篇发言稿。</p><p>大家可以看看出品的内容：</p><p><img src="'+g+'" alt=""></p><p>不得不说，以下这三点太妙了：</p><p>**· **用微小积累对抗焦虑。</p><p>**· **用灵活适应替代固执。</p><p>**· **用内在适应替代外部评价。</p><p>一方面表述逻辑让人记忆深刻，即「要什么不要什么」，有锚点，有解决方案；另一方面，逻辑上一步步推进，抓住本源，也就是从我们内在出发。</p><h2 id="_04" tabindex="-1"><strong>04</strong> <a class="header-anchor" href="#_04" aria-label="Permalink to &quot;**04**&quot;">​</a></h2><p>其实，这只是 Get 笔记本次升级的一个内容。</p><p>还有一个我特别喜欢，那就是：<strong>笔记内提问。</strong></p><p><img src="'+c+'" alt=""></p><p>这是什么意思？</p><p>比如某次直播，我被问到一个问题：做好本职工作就好了，为什么还要提升自己？</p><p>当时我感觉自己的回答不是特别好，于是结束后自己又做了一些思考，并用 Get 笔记进行记录。</p><p>记录之后，我发现自己说得有点啰嗦，于是就在笔记内，选择了「AI助手」，并请它基于我的内容，说说：如何理解「我们为什么要提升能力」。</p><p>可以看到：它的总结比我说的更有逻辑。</p><p><img src="'+_+'" alt=""></p><p><strong>左：我做的笔记 右：在笔记内提问</strong></p><p>于是，我就把这条「追加到当前笔记」。</p><p><img src="'+m+'" alt=""></p><p><strong>↑ 将新笔记追加到了原始笔记后面</strong></p><p>也就是说，当我们记录一条笔记后，就可以顺着这条笔记：</p><p><strong>1.提炼核心内容</strong></p><p><strong>2.延展相关知识</strong></p><p>于是，便形成了知识链条！</p><h2 id="_05" tabindex="-1"><strong>05</strong> <a class="header-anchor" href="#_05" aria-label="Permalink to &quot;**05**&quot;">​</a></h2><p>当然，它还有一些本来就很厉害的功能，我也附在这里：</p><p><img src="'+l+'" alt=""></p><p><img src="'+b+'" alt=""></p><p><img src="'+d+'" alt=""></p><h2 id="_06" tabindex="-1"><strong>06</strong> <a class="header-anchor" href="#_06" aria-label="Permalink to &quot;**06**&quot;">​</a></h2><p>很多人可能不知道，Get 笔记就是「得到 App 」出品的 AI 工具。</p><p>这次更新最打动我的，不仅是功能的强大，更是得到敢向自己护城河动刀——把核心的知识资产开放给 Get 笔记。于是，答案更可靠，毕竟有严选的内容为基础，输出质量自然更有保障。</p><p>如果你也经常需要进行知识管理，真心建议试一试这款软件。</p>',63)])])}const j=t(h,[["render",x]]);export{k as __pageData,j as default};
